{!REQUIRESCRIPT("/soap/ajax/57.0/apex.js")}

try{
var stringPrefix ='{!$Setup.leaseworks__LeaseWorksSettings__c.leaseworks__Package_Prefix__c}';
var retVal= "";

if(stringPrefix == ""){
   retVal =sforce.apex.execute("LWGlobalUtils","CreateAuditSchedule", {leaseId:"{!leaseworks__Lease__c.Id }"});
}
else{
   retVal =sforce.apex.execute("leaseworks/LWGlobalUtils","CreateAuditSchedule", {leaseId:"{! leaseworks__Lease__c.Id }"});
}

}catch(err){
  retVal="Unable to create Audit Records, probably because you don't have necessary permission." + err;
}

window.alert(retVal);
window.location.reload();
